```
if ((*(a1+0x1FE8) == *(a1+0x1FEC) && a3 > 0x62)
    || (a2 == 0 && a3 > 0x62 && a3 <= *(a1+0x48) && a3 <= *(a1+0x2008)))
    return 0;
